        session.context.write('  /agent status                  Show current agent plan\n');
        session.context.write('  /agent run [strict|off]        Execute plan with verification gates\n');
        session.context.write('  /agent verify                  Run typecheck + tests\n');
        session.context.write('  /agent rollback                Undo last write-file step\n');
        session.context.write('  /agent clear                   Clear current agent plan\n');
        session.context.write('  /tools on|off      Enable/disable LLM tool-call dispatch\n');
        session.context.write('  /memory show       Show persistent memory stats/recent entries\n');
        session.context.write('  /memory clear      Clear persistent memory store\n');
        session.context.write('  /show              Show runtime/model info\n');
        session.context.write('  /clear             Clear session chat history\n');
        session.context.write('  /bye               Exit tinker\n');
        session.context.write('\n');
        session.context.write('Type your message directly to chat with AI.\n\n');
