    session.context.write('Commands:\n');
    session.context.write('  /help              Show this help\n');
    session.context.write('  /status            Show project and IR status\n');
    session.context.write('  /commands          List available pack commands\n');
    session.context.write('  /intent <text>     Parse and preview intent\n');
    session.context.write('  /plan <text>       Show plan for intent without executing\n');
    session.context.write('  /ir                Show current IR snapshot\n');
    session.context.write('  /config            Show Lumis config\n');
    session.context.write('  /quit              Exit tinker mode\n');
